```php
<?php
$file = 'data.txt';
if (file_exists($file)) {
    $perms = fileperms($file);
    echo "Current permissions: " . substr(sprintf('%o', $perms), -4) . "\n";
    // Change to owner read/write, group/others read
    chmod($file, 0644);
    echo "Permissions updated.\n";
} else {
    echo "File not found.";
}
?>
```
